module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const color = args.color || 'var(--accent-color)';
const mode = String(args.percent || 'previous');
const showVals = String(args.showvalues) !== 'false';
const minW = Number.isFinite(parseFloat(args.minwidth)) ? Math.max(0, Math.min(100, parseFloat(args.minwidth))) : 18;
const gap = Math.max(0, Math.min(40, Number.isFinite(parseFloat(args.gap)) ? parseFloat(args.gap) : 6));
const radius = Math.max(0, Math.min(30, Number.isFinite(parseFloat(args.radius)) ? parseFloat(args.radius) : 8));
const stages = [];
sections.map((s) => (s || '').trim()).filter(Boolean).forEach((s) => {
  const i = s.lastIndexOf('|');
  if (i < 0) return;
  const v = parseFloat(s.slice(i + 1).replace(/[,\s]/g, ''));
  if (Number.isFinite(v)) stages.push({ label: s.slice(0, i).trim(), v });
});
if (!stages.length) return `<div>(funnel: "Label | value" per section)</div>`;
const top = Math.max(...stages.map((s) => s.v)) || 1;
let html = `\n\n<div class="mdp-mod-funnel" style="--fu-c:${color}; --fu-radius:${radius}px; gap:${gap}px;">`;
stages.forEach((s, i) => {
  const w = Math.max(minW, (s.v / top) * 100);
  const mix = (85 - i * Math.min(16, 60 / stages.length)).toFixed(0);
  let pct = '';
  if (mode !== 'none' && i > 0) {
    const base = mode === 'first' ? stages[0].v : stages[i - 1].v;
    if (base > 0) pct = `<span class="mdp-fu-pct">${((s.v / base) * 100).toFixed(1)}%</span>`;
  }
  const valSpan = showVals ? `<span class="mdp-fu-val">${s.v.toLocaleString('en-US')}</span>` : '';
  html += `<div class="mdp-fu-stagewrap">` +
    `<div class="mdp-fu-stage" style="width:${w.toFixed(1)}%; background: color-mix(in srgb, var(--fu-c) ${mix}%, transparent);">` +
    `<span class="mdp-fu-label">${esc(s.label)}</span>${valSpan}</div>${pct}</div>`;
});
html += `</div>\n\n`;
return html;
